import unittest
from unittest.mock import patch, MagicMock
from app.handlers.classify_ticket import handle_classify

class TestClassifyHandlerFlagRouting(unittest.TestCase):

    @patch("app.handlers.classify_ticket.check_flag", return_value=False)
    @patch("app.handlers.classify_ticket.classify_v1")
    def test_flag_off_routes_to_v1(self, mock_v1, mock_flag):
        mock_v1.return_value = {"category": "billing"}
        result = handle_classify("user-123", "I was charged twice.")
        mock_v1.assert_called_once()
        self.assertEqual(result["_classifier_version"], "v1")

    @patch("app.handlers.classify_ticket.check_flag", return_value=True)
    @patch("app.handlers.classify_ticket.classify_v2")
    def test_flag_on_routes_to_v2(self, mock_v2, mock_flag):
        mock_v2.return_value = {"category": "billing", "confidence": 0.94}
        result = handle_classify("user-456", "I was charged twice.")
        mock_v2.assert_called_once()
        self.assertEqual(result["_classifier_version"], "v2")

    @patch("app.handlers.classify_ticket.check_flag", return_value=True)
    @patch("app.handlers.classify_ticket.classify_v2")
    def test_unknown_flag_evaluates_to_false(self, mock_v2, mock_flag):
        # Simulate registry returning False for unknown flags
        mock_flag.return_value = False
        result = handle_classify("user-789", "I was charged twice.")
        mock_v2.assert_not_called()

if __name__ == "__main__":
    unittest.main()
